            VistoParameter.Value.Should().Be(VistoValue);
            // Check where clause
            result.Value.where.Should().Contain($"[{DBProObservacoesDicInfo.PTabelaNome}].[{DBProObservacoesDicInfo.Visto}] = @{DBProObservacoesDicInfo.Visto}");
